from src.nodes.base import BaseNode

async def execute(self, inputs):
    name = inputs.get('list_name') or self.get_parameter('list_name', '')
    provided = inputs.get('list')
    if provided is None or provided == []:
        lst = BaseNode.memory.get(name) if name else None
    else:
        lst = provided

    length = 0
    try:
        if lst is not None:
            length = len(lst)
    except Exception as e:
        self.log_info(f'Error computing length: {e}')
        length = 0

    await self.set_output('length', length)
    await self.set_output('exec_out', True)
    return {'length': length}
